create table rmais_ws_nf_info_ap (
    id            number not null enable,
    body_ws       clob,
    creation_date date,
    status        varchar2(1 byte)
);

alter table rmais_ws_nf_info_ap
    add constraint rmais_ws_nf_info_ap_pk primary key ( id )
        using index enable;


